package com.pinova.api.controller;import com.pinova.api.assembler.AdminMemberResponseAssembler;import com.pinova.api.request.*;import com.pinova.api.response.*;import com.pinova.api.web.CurrentAdminResolver;import com.pinova.common.api.ApiResponse;import com.pinova.service.AdminMemberService;import jakarta.servlet.http.HttpServletRequest;import jakarta.validation.Valid;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController @RequestMapping("/admin/members") public class AdminMemberController {
    private final AdminMemberService service;private final CurrentAdminResolver resolver;private final AdminMemberResponseAssembler assembler;public AdminMemberController(AdminMemberService s,CurrentAdminResolver r,AdminMemberResponseAssembler a){service=s;resolver=r;assembler=a;}
    @GetMapping public ApiResponse<List<AdminMemberResponse>> list(@RequestParam(required=false)String keyword,@RequestParam(required=false)Short status,HttpServletRequest r){return ApiResponse.success(service.list(resolver.requireCurrentAdmin(r),keyword,status).stream().map(assembler::toResponse).toList());}
    @GetMapping("/{memberNo}") public ApiResponse<AdminMemberResponse> get(@PathVariable String memberNo,HttpServletRequest r){return ApiResponse.success(assembler.toResponse(service.get(resolver.requireCurrentAdmin(r),memberNo)));}
    @PutMapping("/{memberNo}/status") public ApiResponse<AdminMemberResponse> status(@PathVariable String memberNo,@Valid @RequestBody AdminMemberStatusRequest b,HttpServletRequest r){return ApiResponse.success(assembler.toResponse(service.changeStatus(resolver.requireCurrentAdmin(r),memberNo,b.version(),b.status(),b.reason())));}
    @PostMapping("/{memberNo}/revoke-sessions") public ApiResponse<Void> revoke(@PathVariable String memberNo,@Valid @RequestBody AdminReasonRequest b,HttpServletRequest r){service.revokeSessions(resolver.requireCurrentAdmin(r),memberNo,b.reason());return ApiResponse.success(null);}
}
